package types

import (
	"errors"
	"fmt"
	"net"
	"net/url"
	"sort"
	"strings"
)

type URLs []url.URL

func NewURLs(strs []string) (URLs, error) {
	all := make([]url.URL, len(strs))
	if len(all) == 0 {
		return nil, errors.New("no valid URLs given")
	}
	for i, in := range strs {
		in = strings.TrimSpace(in)
		u, err := url.Parse(in)
		if err != nil {
			return nil, err
		}

		switch u.Scheme {
		case "http", "https":
			if _, _, err := net.SplitHostPort(u.Host); err != nil {
				return nil, fmt.Errorf(`URL address does not have the form "host:port": %s`, in)
			}

			if u.Path != "" {
				return nil, fmt.Errorf("URL must not contain a path: %s", in)
			}
		case "unix", "unixs":
		default:
			return nil, fmt.Errorf("URL scheme must be http, https, unix, or unixs: %s", in)
		}
		all[i] = *u
	}
	us := URLs(all)
	us.Sort()
	return us, nil
}

func MustNewURLs(strs []string) URLs {
	urls, err := NewURLs(strs)
	if err != nil {
		panic(err)
	}
	return urls
}

func (us URLs) String() string {
	return strings.Join(us.StringSlice(), ",")
}

func (us *URLs) Sort() {
	sort.Sort(us)
}
func (us URLs) Len() int           { return len(us) }
func (us URLs) Less(i, j int) bool { return us[i].String() < us[j].String() }
func (us URLs) Swap(i, j int)      { us[i], us[j] = us[j], us[i] }

func (us URLs) StringSlice() []string {
	out := make([]string, len(us))
	for i := range us {
		out[i] = us[i].String()
	}

	return out
}

package loki

import (
	"fmt"
	"math"
	"time"

	"github.com/grafana/grafana-plugin-sdk-go/backend"
	"github.com/grafana/grafana-plugin-sdk-go/backend/gtime"
)

// ceilMs rounds the duration to the nearest millisecond that is
// greater than or equal to the input duration.
func ceilMs(duration time.Duration) time.Duration {
	floatMs := float64(duration.Nanoseconds()) / 1000.0 / 1000.0
	ceilMs := math.Ceil(floatMs)
	return time.Duration(ceilMs) * time.Millisecond
}

// durationMax returns the larger of two time.Duration values.
func durationMax(d1 time.Duration, d2 time.Duration) time.Duration {
	if d1.Nanoseconds() >= d2.Nanoseconds() { return d1 }
	return d2
}

// calculateStep determines the appropriate query step interval for Loki queries.
// If no explicit step is provided, it computes one from the interval, time range,
// and resolution. A safe step is also calculated to prevent excessively small steps.
func calculateStep(interval time.Duration, timeRange time.Duration, resolution int64, queryStep *string) (time.Duration, error) {
	if queryStep == nil || *queryStep == "" {
		step := time.Duration(interval.Nanoseconds() * resolution)
		safeStep := timeRange / 11000
		chosenStep := durationMax(step, safeStep)
		return ceilMs(chosenStep), nil
	}
	step, err := gtime.ParseIntervalStringToTimeDuration(*queryStep)
	if err != nil {
		return step, backend.DownstreamError(fmt.Errorf("failed to parse query step: %w", err))
	}
	return time.Duration(step.Nanoseconds() * resolution), nil
}

package failover

import (
	"bufio"
	"fmt"
	"net"
	"net/http"

	"github.com/traefik/traefik/v3/pkg/types"
)

type responseWriter struct {
	http.ResponseWriter

	needFallback    bool
	written         bool
	header          http.Header
	statusCodeRange types.HTTPCodeRanges
}

func (r *responseWriter) Write(b []byte) (int, error) {
	if !r.written {
		r.WriteHeader(http.StatusOK)
	}

	if r.needFallback {
		// As we will fallback, we can discard the response body.
		return len(b), nil
	}

	return r.ResponseWriter.Write(b)
}

func (r *responseWriter) Header() http.Header {
	if r.header == nil {
		r.header = make(http.Header)
	}

	return r.header
}

func (r *responseWriter) WriteHeader(statusCode int) {
	if statusCode >= 100 && statusCode <= 199 && statusCode != http.StatusSwitchingProtocols {
		clear(r.header)

		return
	}

	if !r.written {
		r.written = true
		r.needFallback = r.statusCodeRange.Contains(statusCode)

		if !r.needFallback {
			for k, v := range r.header {
				for _, vv := range v {
					r.ResponseWriter.Header().Add(k, vv)
				}
			}

			r.ResponseWriter.WriteHeader(statusCode)
		}
	}
}

func (r *responseWriter) Flush() {
	if flusher, ok := r.ResponseWriter.(http.Flusher); ok {
		flusher.Flush()
	}
}

func (r *responseWriter) Hijack() (net.Conn, *bufio.ReadWriter, error) {
	if h, ok := r.ResponseWriter.(http.Hijacker); ok {
		return h.Hijack()
	}

	return nil, nil, fmt.Errorf("not a hijacker: %T", r.ResponseWriter)
}

